async function matchResume(candidate_id: string, resume_id: string, job_requisition_ids: string[]): Promise<{match_results: any[], overall_status: string}> {
  const response = await fetch('https://api.robohire.io/v1/match_resume', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ candidate_id, resume_id, job_requisition_ids })
  });
  const data = await response.json();
  return { match_results: data.match_results, overall_status: data.overall_status };
}
